// WeatherApp.jsx
import React, { useRef, useState } from "react";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";

export default function WeatherApp() {
  const [selectedCity, setSelectedCity] = useState("Atlanta, US");

  // 1) PINS live at the app level so Radar + Community can share them
  const [pins, setPins] = useState([
    // sample to prove it works
    { id: crypto.randomUUID(), lat: 33.78, lng: -84.39, type: "rain", message: "Heavy shower!", user: "Noor", timestamp: Date.now() }
  ]);

  // Sections for smooth scrolling (if you’re using sections)
  const nowRef = useRef(null);
  const forecastRef = useRef(null);
  const radarRef = useRef(null);

  const favoriteCities = ["Atlanta, US", "New York, US", "London, UK", "Dubai, AE"];
  const weatherCards = [
    { id: 1, title: "Temperature", value: "28°C", icon: "🌤️" },
    { id: 2, title: "Humidity", value: "65%", icon: "💧" },
    { id: 3, title: "Wind", value: "14 km/h", icon: "💨" },
  ];

  const handleSelectTab = (key) => {
    const map = { now: nowRef, forecast: forecastRef, radar: radarRef };
    const target = map[key];
    if (target?.current) target.current.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  return (
    <div className="relative h-screen overflow-y-auto pb-24">
      {/* FIXED overlay background (yours uses weatherCondition + isDaytime) */}
      <div className="fixed inset-0 -z-10 pointer-events-none">
        <WeatherOverlay weatherCondition="clear" isDaytime={true} />
      </div>

      {/* NOW SECTION */}
      <section ref={nowRef} className="min-h-screen w-full flex flex-col items-center">
        {/* Search */}
        <div className="sticky top-0 z-40 w-full px-4 py-2 bg-black/60 backdrop-blur-md shadow-md flex items-center justify-between">
          <input
            type="text"
            placeholder="Search city..."
            className="flex-1 px-3 py-1 rounded-lg bg-black/50 text-white placeholder-gray-400 outline-none mr-3"
          />
          <button className="text-purple-400 hover:text-purple-300">🔍</button>
        </div>

        {/* Favorites */}
        <div className="w-full px-4 mt-3 flex space-x-3 overflow-x-auto scrollbar-hide">
          {favoriteCities.map((city) => (
            <button
              key={city}
              onClick={() => setSelectedCity(city)}
              className={`px-4 py-2 rounded-full text-sm whitespace-nowrap transition ${
                selectedCity === city
                  ? "bg-purple-500 text-white"
                  : "bg-black/50 text-white hover:bg-purple-500/60"
              }`}
            >
              {city}
            </button>
          ))}
        </div>

        {/* City name */}
        <div className="w-full px-4 mt-4">
          <h1 className="text-2xl font-semibold text-white drop-shadow-md text-left sm:text-center">
            {selectedCity}
          </h1>
        </div>

        {/* Weather cards (mobile stacked, desktop squares) */}
        <div className="w-full sm:hidden flex flex-col space-y-3 px-4 mt-4">
          {weatherCards.map((card) => (
            <div key={card.id} className="w-full bg-black/60 backdrop-blur-md text-white rounded-2xl p-4 flex justify-between items-center shadow-lg">
              <div>
                <h2 className="text-base">{card.title}</h2>
                <p className="text-2xl font-bold">{card.value}</p>
              </div>
              <div className="text-4xl">{card.icon}</div>
            </div>
          ))}
        </div>
        <div className="hidden sm:grid sm:grid-cols-3 gap-4 px-4 w-full max-w-5xl mt-4">
          {weatherCards.map((card) => (
            <div key={card.id} className="bg-black/60 backdrop-blur-md text-white rounded-xl p-4 flex flex-col justify-center items-center shadow-lg aspect-square hover:ring-1 hover:ring-purple-500/40 transition">
              <div className="text-4xl mb-2">{card.icon}</div>
              <h2 className="text-lg">{card.title}</h2>
              <p className="text-2xl font-bold">{card.value}</p>
            </div>
          ))}
        </div>

        {/* Optional hint to scroll */}
        <div className="mt-6 text-white/80 text-sm">
          <button
            onClick={() => forecastRef.current?.scrollIntoView({ behavior: "smooth" })}
            className="underline hover:text-purple-300"
          >
            Scroll to 16‑day forecast ↓
          </button>
        </div>
      </section>

      {/* FORECAST SECTION */}
      <section ref={forecastRef} className="min-h-screen w-full px-4 max-w-5xl mx-auto pt-8">
        <Forecast city={selectedCity} />
      </section>

      {/* RADAR SECTION */}
      <section ref={radarRef} className="min-h-screen w-full px-4 max-w-5xl mx-auto pt-8">
        {/* 2) Pass pins + onAddPin into Radar */}
        <Radar
          city={selectedCity}
          pins={pins}
          onAddPin={(pin) => setPins((prev) => [...prev, pin])}
        />
      </section>

      {/* Bottom bar that jumps to sections */}
      <BottomBar active={"now"} onSelect={handleSelectTab} />
    </div>
  );
}
